// client/src/pages/ProductsPage.jsx
import React, { useState, useEffect } from 'react'; // Import useState and useEffect
import SearchBar from '../components/SearchBar';
import FilterBox from '../components/FilterBox';
import ProductCard from '../components/ProductCard.jsx';
import './ProductsPage.css';

const ProductsPage = () => {
    const [products, setProducts] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);
    const [filters, setFilters] = useState({});
    const [searchQuery, setSearchQuery] = useState('');

    const fetchProducts = async () => {
        setLoading(true);
        setError(null);
        try {
            // Construct query parameters based on search and filters
            const params = new URLSearchParams();
            if (searchQuery) params.append('keyword', searchQuery);
            if (filters.category) params.append('category', filters.category);
            if (filters.minPrice) params.append('minPrice', filters.minPrice);
            if (filters.maxPrice) params.append('maxPrice', filters.maxPrice);

            const response = await fetch(`/api/products?${params.toString()}`);
            if (!response.ok) {
                throw new Error(`HTTP error! status: ${response.status}`);
            }
            const data = await response.json();
            setProducts(data);
        } catch (err) {
            setError('Failed to fetch products: ' + err.message);
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    // Fetch products on component mount and when filters/search change
    useEffect(() => {
        fetchProducts();
    }, [filters, searchQuery]); // Re-run when filters or search query change

    const handleSearch = (query) => {
        setSearchQuery(query);
    };

    const handleFilter = (newFilters) => {
        setFilters(newFilters);
    };

    if (loading) return <h2 style={{textAlign: 'center', marginTop: '50px'}}>Loading products...</h2>;
    if (error) return <h2 style={{textAlign: 'center', marginTop: '50px', color: 'red'}}>{error}</h2>;

    return (
        <div className="products-page container">
            <h1>Our Products</h1>
            <div className="products-header">
                <SearchBar onSearch={handleSearch} />
                <FilterBox onFilter={handleFilter} />
            </div>
            {products.length === 0 ? (
                <p style={{textAlign: 'center', fontSize: '1.2rem', color: 'var(--secondary-color)'}}>No products found matching your criteria.</p>
            ) : (
                <div className="product-list-grid">
                    {products.map(product => (
                        <ProductCard key={product._id} product={product} /> 
                    ))}
                </div>
            )}
        </div>
    );
};

export default ProductsPage;
